export default {
  loadData(queryClause) {
    return `
    query {
        product(${queryClause}) {
          _id
          name
          images
          description
          application
          expirationDate
          preservation
          isPriority
          pictures
          category {
            _id
            name
          }
          recipes{
            _id
            name
          }
          slug
          packing
          tutorial
          status
        }
      }`
  },

  loadDataPager(queryClause) {
    return `
    query {
      searchProducts(${queryClause.whereClause}) {
        items {
          _id
          name
          images
          description,
          application
          expirationDate
          isPriority
          preservation
          pictures
          category {
            _id
            name
          }
          slug
          packing
          tutorial
          status
        }
        total
      }
    }
    `
  },

  create(queryClause) {
    return `
    mutation {
      createProduct(${queryClause}) {
        recordId
      }
    }
    `
  },

  update(queryClause) {
    return `
    mutation {
      updateProduct(${queryClause}) {
        recordId
      }
    }
    `
  },
  delete(queryClause) {
    return `
    mutation {
      deleteProduct(${queryClause}) {
        recordId
      }
    }
    `
  }
}

